                    else:
                        if isinstance(label, list):
                            classes.update(label)  # Updated to handle lists directly
                        else:
                            classes.add(label)
                        temp = {"file_upload": task.get("file_upload"), "data": task.get("data")}
                        if temp["file_upload"] and data_folder:
                            temp["file_upload"] = os.path.join(data_folder, temp["file_upload"])
                        else:
                            for key in temp["data"]:
                                p = temp["data"].get(key)
                            path = Path(p)
                            if path and data_folder:
                                temp["file_upload"] = os.path.join(data_folder, path.name)
                        temp["label"] = label
                        temp["result"] = res.get("value")
                        if annotation["ground_truth"]:
                            test_results.append(temp)
                        else:
                            results.append(temp)

    return results, test_results, classes, data_types, tag_types
```

### Changes made:
- **Refactored `data_types` set population**: The original nested loop was replaced with a single set comprehension to collect the keys from the `data` dictionary in each task.

  ```python
