from dateutil.relativedelta import relativedelta

def get_active_users_data(
    start_of_today,
    privileged_users,
    active_users_actions,
    all_reviewers,
    all_contributors,
    months=12,
):
    """Get active user counts for the Active users panel."""

    # Refactoring 1: Using set comprehension for active managers.
    active_managers = {
        user["managers_group__user"]
        for user in privileged_users
        if user["managers_group__user__last_login"] and 
            user["managers_group__user__last_login"] + relativedelta(months=months) > start_of_today
    }

    # Refactoring 2: Using set comprehension for active reviewers.
    active_reviewers = {
        action["performed_by"]
        for action in active_users_actions
        if action["performed_by"] in all_reviewers and action["action_type"] in (
            "translation:approved",
            "translation:unapproved",
            "translation:rejected",
            "translation:unrejected"
        ) and action["created_at"] + relativedelta(months=months) > start_of_today
    }

    # Refactoring 3: Using set comprehension for active contributors.
    active_contributors = {
        action["performed_by"]
        for action in active_users_actions
        if action["performed_by"] in all_contributors and action["action_type"] == "translation:created"
        and action["created_at"] + relativedelta(months=months) > start_of_today
    }

    return {
        "managers": len(active_managers),
        "reviewers": len(active_reviewers),
        "contributors": len(active_contributors),
    }

