import json

def get_entity_id():
    '''
    与data_util 里面得到大致entity_id相同，区别是 为了更全的匹配mention，将实体名字全部变成小写
    :return:
    '''
    new_entity_alias = new_alias()
    entity_id = {}

    with open('original_data/kb_data', 'r') as f:
        for line in f:
            temDict = json.loads(line)
            subject = temDict['subject']
            subject_id = temDict['subject_id']

            # Set comprehension for alias - Converts all aliases to lowercase.
            alias = {a.lower() for a in temDict['alias']}

            alias.add(entity_clear(subject))

            # Merge alias set with new_entity_alias if the subject exists in new_entity_alias
            if subject in new_entity_alias:
                alias |= new_entity_alias[subject]

            alias.add(subject.lower())

            # Set comprehension for entity_set - Converts all entries in alias to lowercase.
            entity_set = {en.lower() for en in alias}

            # Populate entity_id dictionary
            for n in entity_set:
                n = del_bookname(n)
                if n in entity_id:
                    entity_id[n].append(subject_id)
                else:
                    entity_id[n] = [subject_id]

    return entity_id

